import { Clipboard as ClipboardPrimitive, useClipboard } from '@ark-ui/react/clipboard';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { CheckIcon, CopyIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Clipboard.module.css';

const ClipboardRoot = forwardRef<
  ComponentRef<typeof ClipboardPrimitive.Root>,
  ComponentProps<typeof ClipboardPrimitive.Root>
>(function ClipboardRoot({ className, ...props }, ref) {
  return (
    <ClipboardPrimitive.Root
      ref={ref}
      data-slot="clipboard-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const ClipboardRootProvider = forwardRef<
  ComponentRef<typeof ClipboardPrimitive.RootProvider>,
  ComponentProps<typeof ClipboardPrimitive.RootProvider>
>(function ClipboardRootProvider({ className, ...props }, ref) {
  return (
    <ClipboardPrimitive.RootProvider
      ref={ref}
      data-slot="clipboard-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const ClipboardLabel = forwardRef<
  ComponentRef<typeof ClipboardPrimitive.Label>,
  ComponentProps<typeof ClipboardPrimitive.Label>
>(function ClipboardLabel({ className, ...props }, ref) {
  return (
    <ClipboardPrimitive.Label
      ref={ref}
      data-slot="clipboard-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const ClipboardControl = forwardRef<
  ComponentRef<typeof ClipboardPrimitive.Control>,
  ComponentProps<typeof ClipboardPrimitive.Control>
>(function ClipboardControl({ className, ...props }, ref) {
  return (
    <ClipboardPrimitive.Control
      ref={ref}
      data-slot="clipboard-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const ClipboardInput = forwardRef<
  ComponentRef<typeof ClipboardPrimitive.Input>,
  ComponentProps<typeof ClipboardPrimitive.Input>
>(function ClipboardInput({ className, ...props }, ref) {
  return (
    <ClipboardPrimitive.Input
      ref={ref}
      data-slot="clipboard-input"
      className={clsx(styles.input, normalizeClassName(className))}
      {...props}
    />
  );
});

const ClipboardTrigger = forwardRef<
  ComponentRef<typeof ClipboardPrimitive.Trigger>,
  ComponentProps<typeof ClipboardPrimitive.Trigger>
>(function ClipboardTrigger({ className, ...props }, ref) {
  return (
    <ClipboardPrimitive.Trigger
      ref={ref}
      data-slot="clipboard-trigger"
      className={clsx(styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const ClipboardIndicator = forwardRef<
  ComponentRef<typeof ClipboardPrimitive.Indicator>,
  ComponentProps<typeof ClipboardPrimitive.Indicator>
>(function ClipboardIndicator({ className, children, copied, ...props }, ref) {
  return (
    <ClipboardPrimitive.Indicator
      ref={ref}
      data-slot="clipboard-indicator"
      className={clsx(styles.indicator, normalizeClassName(className))}
      copied={
        copied ?? (
          <span
            aria-hidden="true"
            data-slot="clipboard-indicator-copied-icon"
            className={styles.icon}
          >
            <CheckIcon />
          </span>
        )
      }
      {...props}
    >
      {children ?? (
        <span aria-hidden="true" data-slot="clipboard-indicator-idle-icon" className={styles.icon}>
          <CopyIcon />
        </span>
      )}
    </ClipboardPrimitive.Indicator>
  );
});

const ClipboardValueText = forwardRef<
  ComponentRef<typeof ClipboardPrimitive.ValueText>,
  ComponentProps<typeof ClipboardPrimitive.ValueText>
>(function ClipboardValueText({ className, ...props }, ref) {
  return (
    <ClipboardPrimitive.ValueText
      ref={ref}
      data-slot="clipboard-value-text"
      className={clsx(styles.valueText, normalizeClassName(className))}
      {...props}
    />
  );
});

const ClipboardCopyText = forwardRef<
  ComponentRef<typeof ClipboardPrimitive.Indicator>,
  ComponentProps<typeof ClipboardPrimitive.Indicator>
>(function ClipboardCopyText({ copied = 'Copied', children = 'Copy', ...props }, ref) {
  return (
    <ClipboardIndicator ref={ref} data-slot="clipboard-copy-text" copied={copied} {...props}>
      {children}
    </ClipboardIndicator>
  );
});

const Clipboard = Object.assign(ClipboardRoot, {
  Root: ClipboardRoot,
  RootProvider: ClipboardRootProvider,
  Label: ClipboardLabel,
  Control: ClipboardControl,
  Input: ClipboardInput,
  Trigger: ClipboardTrigger,
  Indicator: ClipboardIndicator,
  CopyText: ClipboardCopyText,
  ValueText: ClipboardValueText,
  useClipboard,
});

export { Clipboard };

@layer ui.components {
  .root {
    display: flex;
    flex-direction: column;
    gap: var(--clipboard-gap, var(--spacing-1-5));
    width: var(--clipboard-width, 100%);
    max-width: var(--clipboard-max-width, none);
    color: var(--clipboard-color, var(--color-foreground));
  }

  .label {
    color: var(--clipboard-label-color, currentColor);
    font-size: var(--clipboard-label-font-size, var(--text-sm));
    font-weight: var(--clipboard-label-font-weight, var(--weight-medium));
    line-height: var(--clipboard-label-line-height, var(--line-height-text-sm));
  }

  .control {
    display: flex;
    align-items: center;
    gap: var(--clipboard-control-gap, var(--spacing-2));
    width: 100%;
  }

  .input {
    box-sizing: border-box;
    width: 100%;
    min-width: 0;
    min-height: var(--clipboard-input-height, var(--input-height-md, var(--size-md)));
    margin: 0;
    border: var(--clipboard-input-border-width, var(--input-border-width, var(--border-width-sm)))
      solid var(--clipboard-input-border-color, var(--input-border-color, var(--color-border)));
    border-radius: var(--clipboard-input-radius, var(--input-radius, var(--radius-md)));
    padding-block: var(--clipboard-input-padding-y, var(--input-padding-y-md, var(--spacing-1)));
    padding-inline: var(--clipboard-input-padding-x, var(--input-padding-x-md, var(--spacing-3-5)));
    background-color: var(--clipboard-input-bg, var(--input-bg, var(--color-background)));
    color: var(--clipboard-input-color, var(--input-color, var(--color-foreground)));
    font: inherit;
    font-size: var(--clipboard-input-font-size, var(--input-font-size-md, var(--text-md)));
    line-height: var(
      --clipboard-input-line-height,
      var(--input-line-height-md, var(--line-height-text-md))
    );
    outline: var(
        --clipboard-input-focus-ring-width,
        var(
          --input-focus-ring-width,
          var(
            --clipboard-input-border-width,
            var(--input-border-width, var(--focus-ring-inset-width, var(--border-width-sm)))
          )
        )
      )
      solid transparent;
    outline-offset: calc(
      var(
          --clipboard-input-focus-ring-offset,
          var(--clipboard-input-border-width, var(--input-border-width, var(--border-width-sm)))
        ) *
        -1
    );
    transition:
      border-color var(--clipboard-transition, var(--input-transition, var(--transition-default))),
      outline-color var(--clipboard-transition, var(--input-transition, var(--transition-default))),
      background-color
        var(--clipboard-transition, var(--input-transition, var(--transition-default))),
      color var(--clipboard-transition, var(--input-transition, var(--transition-default))),
      opacity var(--clipboard-transition, var(--input-transition, var(--transition-default)));

    &::placeholder {
      color: var(
        --clipboard-input-placeholder-color,
        var(--input-placeholder-color, var(--color-muted-foreground))
      );
    }

    &:focus-visible {
      outline-color: var(
        --clipboard-input-focus-ring-color,
        var(--input-focus-ring-color, var(--color-ring))
      );
    }

    &[data-readonly] {
      background-color: var(
        --clipboard-input-readonly-bg,
        var(--input-readonly-bg, var(--clipboard-input-bg, var(--color-background)))
      );
      color: var(
        --clipboard-input-readonly-color,
        var(--input-readonly-color, var(--clipboard-input-color, var(--color-foreground)))
      );
    }

    &[data-disabled] {
      pointer-events: none;
      opacity: var(
        --clipboard-disabled-opacity,
        var(--input-disabled-opacity, var(--opacity-disabled))
      );
    }
  }

  .trigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    gap: var(--clipboard-trigger-gap, var(--button-content-gap, var(--spacing-2)));
    min-height: var(--clipboard-trigger-height, var(--button-size-md, var(--size-md)));
    padding-inline: var(
      --clipboard-trigger-padding-x,
      var(--button-padding-x-md, var(--spacing-4))
    );
    border: var(
        --clipboard-trigger-border-width,
        var(--button-border-width, var(--border-width-sm))
      )
      solid
      var(--clipboard-trigger-border-color, var(--button-outline-border-color, var(--color-border)));
    border-radius: var(--clipboard-trigger-radius, var(--button-radius, var(--radius-md)));
    background-color: var(
      --clipboard-trigger-bg,
      var(--button-outline-bg, var(--color-background))
    );
    color: var(--clipboard-trigger-color, var(--button-outline-color, var(--color-foreground)));
    appearance: none;
    font: inherit;
    font-size: var(--clipboard-trigger-font-size, var(--button-font-size, var(--text-sm)));
    font-weight: var(
      --clipboard-trigger-font-weight,
      var(--button-font-weight, var(--weight-medium))
    );
    line-height: var(
      --clipboard-trigger-line-height,
      var(--button-line-height, var(--line-height-text-sm))
    );
    user-select: none;
    white-space: nowrap;
    cursor: pointer;
    transition:
      border-color var(--clipboard-transition, var(--button-transition, var(--transition-default))),
      background-color
        var(--clipboard-transition, var(--button-transition, var(--transition-default))),
      color var(--clipboard-transition, var(--button-transition, var(--transition-default))),
      opacity var(--clipboard-transition, var(--button-transition, var(--transition-default))),
      box-shadow var(--clipboard-transition, var(--button-transition, var(--transition-default)));

    & :where(svg) {
      width: var(--clipboard-indicator-size, var(--button-icon-size, var(--spacing-4)));
      height: var(--clipboard-indicator-size, var(--button-icon-size, var(--spacing-4)));
      flex-shrink: 0;
    }

    @media (hover: hover) {
      &:hover:not(:disabled, [data-disabled]) {
        background-color: var(
          --clipboard-trigger-bg-hover,
          var(--button-outline-bg-hover, var(--color-accent))
        );
      }
    }

    &:focus-visible {
      outline: var(
          --clipboard-trigger-focus-ring-width,
          var(--button-focus-ring-width, var(--focus-ring-width, var(--border-width-md)))
        )
        solid
        var(--clipboard-trigger-focus-ring-color, var(--button-focus-ring-color, var(--color-ring)));
      outline-offset: calc(
        var(
            --clipboard-trigger-focus-ring-offset,
            var(
              --clipboard-trigger-border-width,
              var(--button-border-width, var(--border-width-sm))
            )
          ) *
          -1
      );
    }

    &:is(:disabled, [data-disabled]) {
      pointer-events: none;
      opacity: var(
        --clipboard-disabled-opacity,
        var(--button-disabled-opacity, var(--opacity-disabled))
      );
      cursor: default;
    }
  }

  .indicator,
  .icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
  }

  .valueText {
    min-width: 0;
    color: var(--clipboard-value-text-color, currentColor);
    font-size: var(--clipboard-value-text-font-size, inherit);
    font-weight: var(--clipboard-value-text-font-weight, inherit);
    line-height: var(--clipboard-value-text-line-height, inherit);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }
}
